spec.expr:
range_sum(
    avg(tariffGrid_value offset -$tariffPriceInterval)
    *
    integrate(
        ((gridPower_value > 0 < $peakPowerLimit) default 0)[$tariffPriceInterval:$energySampleInterval] offset -$tariffPriceInterval
    ) / 3600000
) 
/
range_sum(
    integrate(
        ((gridPower_value > 0 < $peakPowerLimit) default 0)[$tariffPriceInterval:$energySampleInterval] offset -$tariffPriceInterval
    ) / 3600000
)

sort_by_label(
    avg by (title)(
        consumersPower_value{title !~ "$consumerBlocklist"}
        or
        extPower_value{title !~ "$extBlocklist"}
        or
        auxPower_value{title !~ "$auxBlocklist"}
    )
, "title")

and ON(title) 
(consumersPower_value{title=~".+"} or extPower_value{title=~".+"} or auxPower_value{title=~".+"})

sort_by_label(
    avg by (title)(
        consumersPower_value{title !~ "$consumerBlocklist"}
        or
        extPower_value{title !~ "$extBlocklist"}
        or
        auxPower_value{title !~ "$auxBlocklist"}
    )
, "title")

and ON(title) 
(consumersPower_value{title=~".+"} or extPower_value{title=~".+"} or auxPower_value{title=~".+"})

range_last(
    sum(
        integrate(
            ((homePower_value < $peakPowerLimit) default 0)[1d:$energySampleInterval]
        ) / 3600
    )
)
- range_last(
    sum(
        integrate(
            ((consumersPower_value{title!="", title !~ "$consumerBlocklist"} < $peakPowerLimit) default 0)[1d:$energySampleInterval]
        ) / 3600
    )
)
- range_last(
    sum(
        integrate(
            ((extPower_value{title!="", title !~ "$extBlocklist"} < $peakPowerLimit) default 0)[1d:$energySampleInterval]
        ) / 3600
    )
)
- range_last(
    sum(
        integrate(
            ((auxPower_value{title!="", title !~ "$auxBlocklist"} < $peakPowerLimit) default 0)[1d:$energySampleInterval]
        ) / 3600
    )
)

sum(
    integrate(
        ((homePower_value < $peakPowerLimit) default 0)[1h:$energySampleInterval]
    ) / 3600
)
-
sum(
    integrate(
        ((consumersPower_value{title!="", title !~ "$consumerBlocklist"} < $peakPowerLimit) default 0)[1h:$energySampleInterval]
    ) / 3600
)
-
sum(
    integrate(
        ((extPower_value{title!="", title !~ "$extBlocklist"} < $peakPowerLimit) default 0)[1h:$energySampleInterval]
    ) / 3600
)
-
sum(
    integrate(
        ((auxPower_value{title!="", title !~ "$auxBlocklist"} < $peakPowerLimit) default 0)[1h:$energySampleInterval]
    ) / 3600
)

sort_by_label(
    range_last(
        sum by (loadpoint)(
            integrate(
                ((chargePower_value{loadpoint!="", loadpoint !~ "$loadpointBlocklist"} < $peakPowerLimit) default 0)[1d:$energySampleInterval]
            ) / 3600
        )
    )
, "loadpoint")
